window.__QUIZ_DATA__=[{"id":"objective>Mathematics>1996>1","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"The 6th term of a G.P is -2 and its  first term is 18. What is its common ratio?","images":[],"options":{"A":"-1/2","B":"-1/3","C":"1/4","D":"2"},"answer":"B","explanation":"In a G.P; T6 = ar6; since Tn = arn; 1st term ==> a = 18    sixth term ==> ar5 = -2/27; substituting a = 18    \u2234 18(r5) = -2/27; r5 = -2/27 x 1/18 = -1/243    \u2234 r = 5\u221a-1/243 ==> r = -1/3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>2","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"Convert the decimal number 89 to a binary number.","images":[],"options":{"A":"101101","B":"111001","C":"1001001","D":"1011001"},"answer":"D","explanation":"Therefore, he decimal number 89 = 10110012","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>3","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify (21/6 - 12/3) \u00f7 22/3","images":[],"options":{"A":"3/16","B":"7/16","C":"113/24","D":"211/24"},"answer":"A","explanation":"(21/6 - 12/3) \u00f7 22/3 = (13/6 - 5/3) \u00f7 8/3    13 - 106 \u00f7 83 ==> 36 \u00f7 83 = 12 x 38 = 316","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>4","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Simplify 56x-4 \u00f7 14x-8","images":[],"options":{"A":"2x-12","B":"3x-3","C":"4x-4","D":"4x4"},"answer":"D","explanation":"56x-4 \u00f7 14x-8 = 56 x 1/x4 \u00f7 14 x x-8    => 56/x4 \u00f7 14/x8    => 56/x4 x x8/14 = 56/14 x x8/x4    => 4 x x4 = 4x4","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>5","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Simplify log104 + log1025","images":[],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"B","explanation":"log104 + log1025 = log10(4 x 25) = log10100    => log10102 = 2log1010    But log1010 = 1 ==> 2log1010 = 2 x 1 = 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>6","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : PERCENTAGE ERROR","question":"A boy measured the length and breadth of a rectangular lawn as 59.6 m and 40.3 m respectively instead of 60 m and 40 m. What is his percentage error in his calculation of the perimeter of the lawn?","images":[],"options":{"A":"10%","B":"1.4%","C":"0.7%","D":"0.1%"},"answer":"D","explanation":"Erroreneous length = 59.6 m  Erroreneous breadth = 40.3 m  Perimeter = 2(l + b) = 2(59.6 + 40.3) = 2(99.9) = 199.8 m  Accurate length = 60.0 m; Accurate breadth = 40.0 m  Perimeter = 2(60.0 + 40.0) = 2(100.0) = 200.0 m  Error in perimeter = 200.0 - 199.8 = 0.2  % error in perimeter = 0.2/200 x 100% = 20%/100 = 0.1%","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>7","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Find the 9th term of the arithmetic progression 18, 12, 6, 0, -6, ...","images":[],"options":{"A":"-54","B":"-30","C":"30","D":"42"},"answer":"B","explanation":"1st term = 18, common difference = -6  Tn = a + (n - 1); 19 = 18 + 8d = 18 + 8(-6) = 18 - 48 = -30","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>8","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"The shaded portion in the Venn diagram represents?","images":["data:image/png;base64,"],"options":{"A":"X \u22c2 Z1","B":"X \u22c2 Y1","C":"X1 \u22c2 Y","D":"X \u22c2 Y1 \u22c2 Z"},"answer":"D","explanation":"X \u22c2 Y1 \u22c2 Z is the portion common to both X and Z ONLY","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>9","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Expand (2x - 5)(x - 3)","images":[],"options":{"A":"x2 - 11x - 15","B":"2x2 - 11x + 15","C":"2x2 - 5x - 8","D":"x2 - 5x - 15"},"answer":"B","explanation":"(2x - 5)(x - 3) = 2x(x - 3) - 5(x - 3)  = 2x2 - 6x - 5x + 15 = 2x2 - 11x + 15","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>10","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : ALGEBRAIC FRACTIONS","question":"Simplify 5x - y - 4y - x","images":[],"options":{"A":"9x - y","B":"9y - x","C":"1x - y","D":"1y - x"},"answer":"A","explanation":"5x - y - 4y - x = 5x - y - 4-(x - y) = 5x - y + 4x - y  ==> 5 + 4x - y = 9x - y","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>11","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : SIMULTANEOUS LINEAR EQUATIONS IN TWO VARIABLES","question":"If 3p - q = 6 and 2p + 3q = 4, find q","images":[],"options":{"A":"0","B":"1/2","C":"2/3","D":"1"},"answer":"A","explanation":"3p - q = 6 and 2p + 3q = 4. Find q  Multiply first equation by (3) and add to equation (ii)  9p - 3q = 18  2p + 3q = 4   (add)  11p = 22  p = 2; substitute 2 for p in equation (ii) to get q  2(2) + 3q = 4  4 + 3q = 4  3q = 0  \u2234 q = 0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>12","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"M varies directly as n and inversely as the square of p. If M = 3, when n = 2 and p = 1, find M in terms of n and p","images":[],"options":{"A":"M = 2n3p","B":"M = 3n22p2","C":"M = 3n22p","D":"M = 3n2p2"},"answer":"D","explanation":"M \u221d N; M \u221d 1/p2    => M = k(N)/p2; where k is constant    substituting values of m, n and p respectively    3 = k(2)/12; 3 = 2k; k = 3/2    \u2234 M = 3/2np2  ==> M = 3n2p2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>13","subject":"Mathematics","year":"1996","type":"Objective","topic":"NUMBER AND NUMERATION : POSITIVE AND NEGATIVE INTEGERS, RATIONAL NUMBERS","question":"If x is a real number, which of the following is more illustrated on the number line?","images":["data:image/png;base64,"],"options":{"A":"x","B":"x > -2","C":"-2","D":"-2 \u2264 x"},"answer":"D","explanation":"According to the number line shown, -2 is the extreme left value and it is included as a solution; the extreme right value does not include 4 since it is not shaded.  \u2234 The number line has a solution ranging from -2 to 4  This can be represented as -2 \u2264 x","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>14","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Solve the equation 4a + 15a = 3","images":[],"options":{"A":"21/5","B":"12/5","C":"11/3","D":"14/15"},"answer":"B","explanation":"4a + 15a = 3;  20 + 15a = 3 ==> 215a = 31  ==>21=15a;a=2115=75=12/5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>15","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Make p the subject of the formula; y = a + pa - p","images":[],"options":{"A":"2a - ya + y = p","B":"ay - 1y + 1 = p","C":"a(y - 1)y + 1 = p","D":"ayy + 1 = p"},"answer":"C","explanation":"y1=a + pa - p; y(a-p)=1(a+p);ya-yp=a+p  ya-a=yp+p;a(y-1)=p(y+1)  ==> a(y - 1)y + 1 = p","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>16","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Factorize 32x3 - 8xy2","images":[],"options":{"A":"4(4x + y)(2x - y)","B":"(16x - y)(2x + y)","C":"8x(2x - y)","D":"8x(2x + y)(2x - y)"},"answer":"D","explanation":"Factorize 32x3 - 8xy2; 8(4x3 - xy2)  = 8x(4x2 - y2) = 8x[(2x)2 - y2] = 8x(2x + y)(2x - y)","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>17","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The roots of a quadratic equation are -1/4 and 3. The quadratic equation is:","images":[],"options":{"A":"4x2 - 13x - 3 = 0","B":"4x2 - 11x - 3 = 0","C":"4x2 + 11x - 3 = 0","D":"3x2 - 11x - 3 = 0"},"answer":"B","explanation":"roots of quadratic equations are -1/4 and 3    sum of roots = 3 + (-1/4) = 11/4 or 23/4    product of roots = 3 x (-1/4) = -3/4    \u2234 equation = x2 - (sum of roots)x + product of roots = 0    = x2 - (11/4)x + (-3/4) = 0    = x2 - (11/4)x - 3/4 = 0    multiply through by (4)    ==> 4x2 - 11x - 3 = 0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>18","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"The graph 2y = 5x2 - 3x - 2 cuts the y-axis at the point","images":[],"options":{"A":"(1, 0)","B":"(-2/5, 0)","C":"(0, -1)","D":"(0, -2)"},"answer":"C","explanation":"2y = 5x2 - 3x - 2  The graph cuts y-axis at the point where x = 0  \u2234 when x = 0; 2y = 5(0)2 - 3(0) - 2; 2y = -2 ==> y = -1  \u2234 coordinate of point of intersection with y-axis = (0, -1)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>19","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram below, O is the centre of the circle of radius 3.5 cm. \u2220POQ = 60o.     Use this information to answer questions  below  [Take \u03c0 = 22/7]    What is the length of the major arc PXQ?","images":["data:image/png;base64,"],"options":{"A":"22 cm","B":"181/3 cm","C":"11 cm","D":"91/6 cm"},"answer":"B","explanation":"Reflex angle PXQ = 360o - 60o = 300o  \u2234  lengthofarcPXQ=300360x2x227x3.5=5 x 113=181/3 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>20","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram below, O is the centre of the circle of radius 3.5 cm. \u2220POQ = 60o.     Use this information to answer questions  below  [Take \u03c0 = 22/7]  What is the area of the minor sector POQ?","images":["data:image/png;base64,"],"options":{"A":"1481/2 cm2","B":"77 cm2","C":"321/12 cm2","D":"65/12 cm2"},"answer":"D","explanation":"AreaofminorsectorPOQ=60360x227x72x72=7712=65/12 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>21","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"If the hypotenuse of a right-angled isosceles triangle is 2, what is the length of each of the other sides?","images":[],"options":{"A":"1\u221a2","B":"\u221a2 - 1","C":"1","D":"\u221a2"},"answer":"D","explanation":"Using pythagoras theorem  x2 + x2 = 22  2x2 = 4  x2 = 2  x = \u221a2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>22","subject":"Mathematics","year":"1996","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Find, correct to 1 decimal place, the volume of a cylinder of height 8 cm and base radius 3 cm. [Take \u03c0 = 22/7]","images":[],"options":{"A":"503.0 cm3","B":"300.0 cm3","C":"250.0 cm3","D":"226.2 cm3"},"answer":"D","explanation":"volume of cylinder = \u03c0r2h = 3.142 x 3 x 3 x 8 = 226.2 cm3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>23","subject":"Mathematics","year":"1996","type":"Objective","topic":"MENSURATION : AREAS","question":"One side of a rectangle is 8 cm and the diagonal is 10 cm. What is the area of the rectangle?","images":[],"options":{"A":"80 cm2","B":"48 cm2","C":"40 cm2","D":"36 cm2"},"answer":"B","explanation":"PR = diagonal  Using pythagoras theorem  PR2 = PQ2 + QR2  102 = 82 + x2  x2 = 102 - 82  x2 = 100 - 64  x2 = 36  x = 6  Area of rectangle = l x b = 8 x 6 = 48 cm2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>24","subject":"Mathematics","year":"1996","type":"Objective","topic":"MENSURATION : LONGITUDES AND LATITUDES","question":"Two towns X and Y both on latitude 60oS have longitude 27oE and 33oW respectively. Find to the nearest kilometer, the distance between X and Y measured along the parallel of latitude.  [Take 2\u03c0R = 4 x 104 km, where R is the radius of earth]","images":[],"options":{"A":"28850 km","B":"16667 km","C":"8333 km","D":"3333 km"},"answer":"D","explanation":"X and Y lies on latitude 60oS (small circle)  Radius of latitude 60oS = Rcos\u03b8; where \u03b8 = 60o  Town X on 27oE, Town Y on 33oW.  since one is on the east and the other at west, we add longitudes  \u223427o+33o=60o;distance=60360x2\u03c0Rcos60o  =16x4x104x12=4 x 10412  = 0.333 x 104 = 3333 km","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>25","subject":"Mathematics","year":"1996","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The angle of a sector of a circle of radius 35 cm is 288o. Find the perimeter of the sector.  [Take \u03c0 = 22/7]","images":[],"options":{"A":"246 cm","B":"211 cm","C":"141 cm","D":"114 cm"},"answer":"A","explanation":"Perimeterofsector=\u03b8360x2\u03c0r+2r  =288360x2x227x35+2(35)  8 x 22 + 70 = (176 + 70) cm = 246 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>26","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"How many sides has a polygon if the sum of its interior angle is 1440o?","images":[],"options":{"A":"6","B":"7","C":"8","D":"10"},"answer":"D","explanation":"sum of all interior angles of an n-sided polygon is given as (2n - 4) x 90  \u2234 (2n - 4) x 90 = 1440  18n - 36 = 144  18n = 180  \u2234 n = 10","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>27","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"Each interior angle of a regular nonagon (nine sided polygon) is equal to","images":[],"options":{"A":"160o","B":"144o","C":"140o","D":"132o"},"answer":"C","explanation":"nonagon = 9 sided polygon    sum of interior angles = (2n - 4) x 90    each interior angle = (2n - 4) x 90n  = (2(9) - 4) x 909=140o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>28","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, find x correct to the nearest degree","images":["data:image/png;base64,"],"options":{"A":"15o","B":"25o","C":"26o","D":"36o"},"answer":"C","explanation":"since vertically opposite angles are equal then the four angles of the quadrilateral from left to right are respectively 4x, 5x, 2x and 3x.  \u2234 4x + 5x + 2x + 3x = 360o; 14x = 360o  \u2234x=36014=255/7o  = 26o to nearest degree","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>29","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, TRQ is a straight line, find p, if p = 1/3(a + b + c).","images":["data:image/png;base64,"],"options":{"A":"45o","B":"60o","C":"90o","D":"120o"},"answer":"A","explanation":"a + b + c + p = 180o (sum of angles on a straight line)  p = 180o - a - b - c  1/3(a + b + c) = 180o - a - b - c  a + b + c = 3(180o - a - b - c)  a + b + c = 540o - 3a - 3b - 3c  4a + 4b + 4c = 540o  4(a + b + c) = 540o  a + b + c = 135o  p = 1/3(a + b + c) = 135/3 = 45o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>30","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : CONSTRUCTION","question":"Which of the following is not true? You may construct a","images":[],"options":{"A":"triangle given all the three sides","B":"triangle given one side and two angles","C":"triangle given two sides and the included angle","D":"quadrilateral given all the four sides"},"answer":"D","explanation":"A triangle can be constructed when all the three sides are given, when one side is given and two angles it can also be constructed.  When two sides and an included angle is given a triangle can also be constructed; likewise a parallelogram, when two adjacent sides and the diagonal joining them are given.  \u2234 A quadrilateral cannot be constructed when all the four sides are given except with some included angle or with one or two of its diagonal given.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>31","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram below, PQ is parallel to RST, |RS| = |SQ| = |TQ and \u2220PQR = 35o. Calculate \u2220SQT.","images":["data:image/png;base64,"],"options":{"A":"30o","B":"35o","C":"40o","D":"70o"},"answer":"C","explanation":"\u2220PQR = \u2220QRS = 35o (alternate angles are equal)  \u2220QRS = \u2220SQR = 35o (base angles of isoceles triangle are equal)  \u2220QST = \u2220QRS + \u2220SQR (ext. angle of a triangle equals two opposite int. angles)  \u2220QST = 35o + 35o = 70o  \u2220QST = \u2220STQ = 70o (base angles of isoceles triangle are equal)  \u2220QST + \u2220STQ + \u2220SQT = 180o (sum of angles in a triangle)  70o + 70o + \u2220SQT = 180o  140o + \u2220SQT = 180o  \u2220SQT = 180o - 140o  \u2234 \u2220SQT = 40o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>32","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram below, |PQ| = |PS| and |QR| = |SR|. Which of the following is/are true?    i.   The line PR bisects \u2220QRS.  ii.  The line PR is perpendicular bisector of the line segment QS  iii. Every point on PR is equidistant from SP and QP","images":["data:image/png;base64,"],"options":{"A":"I only","B":"II only","C":"I and II only","D":"I and III only"},"answer":"D","explanation":"The figure shown is a kite. The diagonals bisect the angles.  The diagonals meet at right angle only if it is a rhombus. Every points on the diagonal is equidistant from angles opposite to it: (i) and (iii) only are true","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>33","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : TRIANGLES AND POLYGONS","question":"In the diagram, \u2220PMN = \u2220PRQ and \u2220PNM = \u2220PQR. If |PM| = 3 cm, |MQ| = 7 cm and |PN| = 5 cm, find |NR|","images":["data:image/png;base64,"],"options":{"A":"1 cm","B":"3 cm","C":"31/2 cm","D":"5 cm"},"answer":"A","explanation":"In the figure, PMN is similar to PRQ their corresponding sides are in ratio (proportional)  \u2234MPPN=PRPQ\u223435=53+NR7==>35=5 + NR10  30 = 25 + 5NR; 5 = 5NR   \u2234 NR = 1 cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>34","subject":"Mathematics","year":"1996","type":"Objective","topic":"ALGEBRAIC PROCESSES : DRAWING TANGENTS TO CURVES TO DETERMINE THE GRADIENT AT A GIVEN POINT","question":"In the diagram below, PQ is a tangent to the circle MTN at T. What is the size of \u2220MTN?","images":["data:image/png;base64,"],"options":{"A":"52o","B":"54o","C":"66o","D":"72o"},"answer":"C","explanation":"Given PQ = tangent; then \u2220QTN = \u2220TMN (angle between a tangent and a chord at the point of contact is equal to angle in the alternate segment)  \u2234 \u2220M = 62o  But \u2220MTN + \u2220M + \u2220N = 180o (sum of angles in a triangle)  \u2220MTN + 62o + 52o = 180o; \u2220MTN + 114o = 180o  \u2220MTN = 66o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>35","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, KLMN is a cyclic quadrilateral. |KL| = |KN|, \u2220NKM = 55o and \u2220KML = 40o. Find \u2220LKM","images":["data:image/png;base64,"],"options":{"A":"35o","B":"40o","C":"45o","D":"50o"},"answer":"C","explanation":"\u2220NKM = \u2220NLM = 55o (angles in the same segment are equal)  \u2220MAL = 180o - (55o + 40o) = 180o - 95o = 85o (sum of angles in a triangle)  \u2220MAL = \u2220NAK = 85o (vertically opposite angles are equal)  \u2220KNA = 180o - (55o + 85o) = 180o - 140o = 40o (sum of angles in a triangle)  \u2220KNA = \u2220KLA = 40o (base angles of isoceles triangle are equal)  Now from \u2206NKL  \u2220LKM + 55o + 40o + 40o = 180o (sum of angles in a triangle)  \u2220LKM + 135o = 180o  \u2220LKM = 180o - 135o  \u2234 \u2220LKM = 45o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>36","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram below, In the diagram below, \u2220SPQ = 79o. Find \u2220SRQ","images":["data:image/png;base64,"],"options":{"A":"11o","B":"391/2o","C":"79o","D":"101o"},"answer":"D","explanation":"\u2220SPQ + \u2220SRQ = 180o (opposite angles of a cyclic quadrilateral are supplementary)  79o + \u2220SRQ = 180o  \u2220SRQ = 180o - 79o = 101o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>37","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Two angles (a + 31)o and (b - 49)o are adjacent angles on a straight line. Which of the following is true?","images":[],"options":{"A":"a + b = 198o","B":"a + b = 180o","C":"a + b = 162o","D":"a + b = 100o"},"answer":"A","explanation":"(a + 31)o + (b - 49)o = 180o (adjacent angles on a straight line)  ao + 31o + bo - 49o = 180o  ao + bo - 18o = 180o  ao + bo = 180o + 18o  \u2234 ao + bo = 198o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>38","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The trapezium PQRS has |PS| = |PQ|, PQ is parallel to SR, \u2220PQS = 34o and \u2220SPQ = 2\u2220SRQ. Find the size of angle \u2220SQR","images":["data:image/png;base64,"],"options":{"A":"58o","B":"68o","C":"78o","D":"90o"},"answer":"D","explanation":"\u2220PSQ = \u2220PQS = 34o (base angles of isoceles triangle are equal)  \u2234 \u2220SPQ = 180o - (34o + 34o) = 180o - 68o = 112o  But \u2220SPQ = 2\u2220SRQ  \u2234 112o = 2\u2220SRQ ==> \u2220SRQ = 56o  PQ||SR \u2234 \u2220PQS = \u2220QSR (alternate angles are equal)  \u2234 \u2220QSR + \u2220SRQ + \u2220SQR = 180o (sum of angles in a triangle)  ==> 34o + 56o + \u2220SQR = 180o; \u2220SQR = 180o - 90o  \u2220SQR = 90o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>39","subject":"Mathematics","year":"1996","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, AB, CD and XY are straight lines intersecting at W. Find \u2220CWX?","images":["data:image/png;base64,"],"options":{"A":"20o","B":"80o","C":"100o","D":"120o"},"answer":"B","explanation":"\u2220CWX = \u2220YWD (vertically opposite angles are equal)  But \u2220AWY + \u2220YWD + \u2220DWB = 180o (sum of angles on a straight line)  60o + \u2220CWX + 40o = 180o; \u2220CWX + 100o = 180o  \u2220CWX = 80o","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>40","subject":"Mathematics","year":"1996","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If sin \u03b8 = cos \u03b8, for 0o \u2264 \u03b8 \u2264 360o, find the values of \u03b8.","images":[],"options":{"A":"45o, 225o","B":"135o, 315o","C":"45o, 315o","D":"135o, 225o"},"answer":"A","explanation":"sin \u03b8 = cos \u03b8 for 0 \u2264 \u03b8 \u2264 360o;  if \u03b8 o (acute angle); for sin \u03b8 = cos \u03b8 ==> 45o  since sine \u03b8 and cosine \u03b8 are negative in the 3rd quadrant  180o + \u03b8 = 180o + 45o = 225o  \u2234 solutions are \u03b8 = 45o, 225o","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>41","subject":"Mathematics","year":"1996","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"If tan x = 22/5, find the value of sin x, 0o \u2264 \u03b8 \u2264 90o.","images":[],"options":{"A":"5/13","B":"5/12","C":"144/169","D":"12/13"},"answer":"D","explanation":"tan x = 22/5 ==> tan x = 12/5  since 0 \u2264 x \u2264 90o i.e x is acute  using pythagoras theorem  AC2 = AB2 + BC2; AC2 = 122 + 52 = 144 + 25  AC2 = 169 ==> AC = 13  sinex=oppositehypotenuse==>sinx=12/13","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>42","subject":"Mathematics","year":"1996","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A town P is 150 km from a town Q in the direction of 050o. What is the bearing of Q from P?","images":[],"options":{"A":"050o","B":"130o","C":"230o","D":"270o"},"answer":"C","explanation":"Bearing of P from Q = 050o  \u2234 Bearing of of Q from P = 180o + 50o = 230o","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>43","subject":"Mathematics","year":"1996","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"The angle of elevation of the top X of a vertical pole from a point P on a level ground is 60o. The distance from P to the foot of the pole is 55m. Without using tables, find the height of the pole.","images":[],"options":{"A":"50/3 m","B":"50 m","C":"55\u221a3 m","D":"60 m"},"answer":"C","explanation":"tan\u03b8=oppositeadjacent  tan60o=H55;Heightofpole(H)=tan60ox55=\u221a3 x 55 = 55\u221a3m","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>1996>44","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The number of goals scored by a football team in 20 matches is shown in the table below  No of goals 0 1 2 3 4 5No of matches 3 5 7 4 1 0   Use the table to answer questions  below    What is the mean goal scored?","images":[],"options":{"A":"0.75","B":"1.75","C":"1.9","D":"2"},"answer":"B","explanation":"Meangoalscored=\u2211fx\u2211f  = (0 x 3) + (1 x 5) + (2 x 7) + (3 x 4) +  (4 x 1) + (5 x 0)3 + 5 + 7 + 4 + 1 + 0 = 0 + 5 + 14 + 12 + 4 + 020 = 3520 = 1.75","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>45","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The number of goals scored by a football team in 20 matches is shown in the table below  No of goals 0 1 2 3 4 5No of matches 3 5 7 4 1 0   Use the table to answer questions  below  What is the modal goal scored?","images":[],"options":{"A":"0","B":"1","C":"2","D":"5"},"answer":"C","explanation":"Modal goal scored = Goal with highest frequency ==> 2","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>1996>46","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The cumulative frequency curve may be used to find the","images":[],"options":{"A":"Variance","B":"Standard deviation","C":"Mode","D":"Median"},"answer":"D","explanation":"Cumulative graphs can also be used to calculate the Median of given data. If you draw both the curves on the same graph, the point at which they intersect, the corresponding value on the x-axis, represents the Median of the given data set.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>47","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The marks obtained by pupils of a class are grouped as shown below: 0 - 4, 5 - 9, 10 -14, 15 -19. Which of the following is/are not true?  i. The mid values of the grouped marks are 2, 7, 12 and 17.  ii. The class interval is 4  iii. The class boundaries are 0.5, 4.5, 9.5, 14.5 and 19.5","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I and II only"},"answer":"B","explanation":"The marks are shown below:  0 - 4, 5 - 9, 10 -14, 15 -19.  (i) The mid values of the grouped marks are 2, 7, 12, 17 ==> this is true  (ii) Class interval is (0, 1, 2, 3, 4) = 5 not 4 ==> this is not true  (iii) Class boundaries are 0.5, 4.5, 9.5, 14.5 and 19.5 ==> this is true  Only (ii) is not true","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>48","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"What percentage of observations lie outside interquartile range of any distribution?","images":[],"options":{"A":"121/2%","B":"25%","C":"50%","D":"621/2%"},"answer":"C","explanation":"Interquartile range = Q3 - Q1  = Upper Quartile - Lower Quartile  = 75% - 25% = 50%  \u2234 Values that lie outside interquartile range in any distribution is 100% - 50% ==> 50%","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>49","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"A bag containing 3 red, 4 black and 5 green identical balls, Two balls are picked at random, one after the other without replacement, find the probability that one is red and the other is green?","images":[],"options":{"A":"23","B":"511","C":"522","D":"524"},"answer":"C","explanation":"3 red balls; 4 black balls and 5 green balls.    Two balls picked at random without replacement.    Probabilty that one is red the other is green will be    Pr(1st red and second green) or Pr(1st green and second red)    Pr(1stred)=312=14  Pr(2ndgreen)=511  Pr(1stred,2ndgreen)=14x511=544  Pr(1stgreen)=512  Pr(2ndred)=311  Pr(1stgreen,2ndred)=512x311=544  Hence,Pr(oneisredandtheothergreen)=544+544=522","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>1996>50","subject":"Mathematics","year":"1996","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The table gives the distribution of outcomes obtained when a die was rolled 100 times.  No of die 1 2 3 4 5 6Frequency 18 14 20 16 15 17  What is the experimental probability that it shows at most 4 when rolled again?","images":[],"options":{"A":"8/25","B":"12/25","C":"13/25","D":"17/25"},"answer":"D","explanation":"Experimental probabilty that it shows at most 4 when rolled again will be sum of the frequencies below 4 and including 4 but not more than 4 divided by total frequencies.  = 18 + 14 + 20 + 1618 + 14 + 20 + 16 + 15 + 17 = 68100 = 1725","marks":"1","difficulty":"2"}];